  user(id: ID!): User
  goals(userId: ID!): [Goal]
  habits(userId: ID!): [Habit]
  aiAdvices(userId: ID!): [AIAdvice]
}

type Mutation {
  registerUser(username: String!, email: String!, password: String!): AuthPayload
  createGoal(userId: ID!, title: String!, description: String!, deadline: String!): Goal
  createHabit(userId: ID!, name: String!, frequency: String!, reminders: [String]!): Habit
